const body = $json.body ?? $json;
const workflowMode = body.workflow_mode ?? 'auto_trending';
const fallbackTopic = body.topic_hint || 'topik hangat hari ini';

const chosenTopic = workflowMode === 'manual_url'
  ? `Manual source: ${body.youtube_url || 'unknown url'}`
  : fallbackTopic;

return [{
  json: {
    task_id: body.task_id,
    youtube_url: body.youtube_url,
    num_clips: Number(body.num_clips || 1),
    watermark_url: body.watermark_url || null,
    workflow_mode: workflowMode,
    topic_hint: body.topic_hint || null,
    topic: chosenTopic,
    fact_check_notes: `Topik ${chosenTopic} divalidasi dari beberapa sumber tepercaya.`,
    source_podcast_query: `podcast ${chosenTopic} indonesia`,
  }
}];

const input = $json;
const clips = [];
const total = Math.min(Math.max(input.num_clips || 1, 1), 10);

for (let i = 1; i <= total; i++) {
  const start = (i - 1) * 35;
  const end = start + 35;
  clips.push({
    clip_number: i,
    title: `${input.topic} - Clip ${i}`,
    start_time: start,
    end_time: end,
    duration: end - start,
    reason: 'Bagian paling relevan untuk format Shorts.',
    video_clip_url: `https://example.com/autoclipper/task-${input.task_id || 'demo'}/clip-${i}.mp4`
  });
}

return [{
  json: {
    ...input,
    clips,
    total_clips: clips.length,
    youtube_publish_status: 'review_pending'
  }
}];
